rules:
match /databases/{database}/documents {
  match /usuarios/{userId} {
    allow create: if true;
    allow read: if request.auth != null && request.auth.uid == userId;
    allow update, delete: if request.auth != null && request.auth.uid == userId;
  }
  match /cobradores/{cobradorId} {
    allow read: if request.auth != null;
    allow create: if request.auth != null && request.auth.token.role == 'Admin';
    allow update, delete: if request.auth != null && (request.auth.token.role == 'Admin' || request.auth.uid == cobradorId);
  }
  match /clientes/{clienteId} {
    allow read: if request.auth != null;
    allow create: if request.auth != null && (request.auth.token.role == 'Admin' || request.auth.token.role == 'Cobrador');
    allow update, delete: if request.auth != null && (request.auth.token.role == 'Admin' || request.auth.token.role == 'Cobrador');
  }
  match /creditos/{creditoId} {
    allow read: if request.auth != null;
    allow create: if request.auth != null && (request.auth.token.role == 'Admin' || request.auth.token.role == 'Cobrador');
    allow update, delete: if request.auth != null && (request.auth.token.role == 'Admin' || request.auth.token.role == 'Cobrador');
  }
  match /{document=**} {
    allow read, write: if false;
  }
}
